import * as t from "io-ts";
import { BaseIntent, BaseIntentWithRecipients } from "./baseIntent";
import { intentTypes } from "./intentType";

/**
 * @title Hypeevm Spot Transfer Intent
 */
export const HypeevmSpotTransferIntent = t.intersection([
  BaseIntent,
  BaseIntentWithRecipients,
  t.type({
    intentType: intentTypes.spotTransfer,
  }),
]);

export type HypeevmSpotTransferIntent = t.TypeOf<
  typeof HypeevmSpotTransferIntent
>;
